package main

import (
	"context"
	"database/sql"
	"fmt"
	"net/http"
	"strconv"

	"github.com/gorilla/mux"
)

type Order struct {
	ID       int    `json:"id"`
	Customer string `json:"customer"`
	Product  string `json:"product"`
}

func main() {
	router := mux.NewRouter()

	// Define a route for getting order details by ID
	router.HandleFunc("/orders/{orderID}", func(w http.ResponseWriter, r *http.Request) {
		// Extract the order ID from the URL path
		vars := mux.Vars(r)
		orderID, err := strconv.Atoi(vars["orderID"])
		if err != nil {
			http.Error(w, "Invalid order ID", http.StatusBadRequest)
			return
		}

		// Query the database for the order details
		db := r.Context().Value("database").(*sql.DB)
		order := Order{}
		err = db.QueryRow(`SELECT * FROM orders WHERE id = $1`, orderID).Scan(&order.ID, &order.Customer, &order.Product)
		if err != nil {
			http.Error(w, "Order not found", http.StatusNotFound)
			return
		}

		// Marshal the order details into JSON and send them back to the client
		json, _ := json.Marshal(order)
		w.Header().Set("Content-Type", "application/json")
		w.Write(json)
	}).Methods("GET")

	// Start the HTTP server
	http.ListenAndServe(":8080", router)
}